:"33.38%"} -->\n<div class="wp-block-column" style="flex-basis:33.38%"><!-- wp:paragraph {"style":{"color":{"text":"#000000"},"typography":{"fontSize":"17px"}}} -->\n<p class="has-text-color" style="color:#000000;font-size:17px"><em>Nature</em>, in the common sense, refers to essences unchanged by man; space, the air, the river, the leaf.&nbsp;<em>Art</em>&nbsp;is applied to the mixture of his will with the same things, as in a house, a canal, a statue, a picture. </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {"style":{"color":{"text":"#000000"},"typography":{"fontSize":"17px"}}} -->\n<p class="has-text-color" style="color:#000000;font-size:17px">But his operations taken together are so insignificant, a little chipping, baking, patching, and washing, that in an impression so grand as that of the world on the human mind, they do not vary the result.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {"width":"33%"} -->\n<div class="wp-block-column" style="flex-basis:33%"><!-- wp:spacer {"height":"2vw"} -->\n<div style="height:2vw" aria-hidden="true" class="wp-block-spacer"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:image {"sizeSlug":"large","linkDestination":"none"} -->\n<figure class="wp-block-image size-large"><img src="https://s.w.org/images/core/5.8/outside-01.jpg" alt="Le soleil se couchant derrière une forêt dense." /></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {"width":"33.62%"} -->\n<div class="wp-block-column" style="flex-basis:33.62%"><!-- wp:image {"sizeSlug":"large","linkDestination":"none"} -->\n<figure class="wp-block-image size-large"><img src="https://s.w.org/images/core/5.8/outside-02.jpg" alt="Des éoliennes se tiennent sur une plaine herbeuse, avec un ciel bleu en arrière-plan." /></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns {"align":"wide","style":{"spacing":{"blockGap":{"left":"3vw"}}}} -->\n<div class="wp-block-columns alignwide"><!-- wp:column {"width":"69%"} -->\n<div class="wp-block-column" style="flex-basis:69%"><!-- wp:image {"sizeSlug":"large","linkDestination":"none"} -->\n<figure class="wp-block-image size-large"><img src="https://s.w.org/images/core/5.8/outside-03.jpg" alt="Le soleil brille au dessus d’une crête donnant sur le bord de mer. Plus loin, une voiture est visible." /></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {"verticalAlignment":"center","width":"33%"} -->\n<div class="wp-block-column is-vertically-aligned-center" style="flex-basis:33%"><!-- wp:spacer {"height":"2vw"} -->\n<div style="height:2vw" aria-hidden="true" class="wp-block-spacer"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:paragraph {"style":{"color":{"text":"#000000"},"typography":{"fontSize":"17px"}}} -->\n<p class="has-text-color" style="color:#000000;font-size:17px">Sans doute n’avons-nous pas de questions à poser qui soient sans réponse. Nous devons faire confiance à la perfection de la création au point de croire que, quelle que soit la curiosité que l’ordre des choses a éveillée dans notre esprit, l’ordre des choses peut la satisfaire. La condition de chaque homme est une solution en hiéroglyphes aux questions qu’il poserait.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->";}i:11;O:8:"stdClass":7:{s:2:"id";i:1355;s:5:"title";O:8:"stdClass":1:{s:8:"rendered";s:40:"Média et texte avec image sur la gauche";}s:7:"content";O:8:"stdClass":2:{s:8:"rendered";s:644:"\n<div class="wp-block-media-text alignfull is-stacked-on-mobile is-vertically-aligned-center"><figure class="wp-block-media-text__media"><img decoding="async" src="https://s.w.org/images/core/5.8/architecture-04.jpg" alt="Vue de près d’un détail architectural." /></figure><div class="wp-block-media-text__content">\n<h3 class="wp-block-heading has-text-align-center has-text-color" style="color:#000000"><strong>Espaces ouverts</strong></h3>\n\n\n\n<p class="has-text-align-center has-extra-small-font-size wp-block-paragraph"><a href="#">Voir l’étude de cas <span aria-hidden="true" class="wp-exclude-emoji">↗</span></a></p>\n</div></div>\n";s:9:"protected";b:0;}s:4:"meta";O:8:"stdClass":10:{s:14:"_crdt_document";s:0:"";s:31:"jetpack_post_was_ever_published";b:0;s:13:"wpop_keywords";s:0:"";s:16:"wpop_description";s:74:"Bloc média et bloc texte, avec l’image à gauche et le texte à droite.";s:19:"wpop_viewport_width";i:1200;s:16:"wpop_block_types";a:1:{i:0;s:0:"";}s:11:"wpop_locale";s:5:"fr_FR";s:15:"wpop_wp_version";s:0:"";s:25:"wpop_contains_block_types";s:43:"core/heading,core/media-text,core/paragraph";s:9:"footnotes";s:0:"";}s:14:"category_slugs";a:1:{i:0;s:6:"banner";}s:13:"keyword_slugs";a:2:{i:0;s:4:"core";i:1;s:8:"featured";}s:15:"pattern_content";s:858:"<!-- wp:media-text {"align":"full","mediaType":"image","verticalAlignment":"center"} -->\n<div class="wp-block-media-text alignfull is-stacked-on-mobile is-vertically-aligned-center"><figure class="wp-block-media-text__media"><img src="https://s.w.org/images/core/5.8/architecture-04.jpg" alt="Vue de près d’un détail architectural." /></figure><div class="wp-block-media-text__content"><!-- wp:heading {"textAlign":"center","level":3,"style":{"color":{"text":"#000000"}}} -->\n<h3 class="wp-block-heading has-text-align-center has-text-color" style="color:#000000"><strong>Espaces ouverts</strong></h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {"align":"center","fontSize":"extra-small"} -->\n<p class="has-text-align-center has-extra-small-font-size"><a href="#">Voir l’étude de cas ↗</a></p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:media-text -->";}i:12;O:8:"stdClass":7:{s:2:"id";i:1325;s:5:"title";O:8:"stdClass":1:{s:8:"rendered";s:44:"Large en-tête avec texte aligné à gauche.";}s:7:"content";O:8:"stdClass":2:{s:8:"rendered";s:1467:"\n<div class="wp-block-cover alignfull" style="min-height:800px;aspect-ratio:unset;"><span aria-hidden="true" class="wp-block-cover__background has-background-dim-60 has-background-dim"></span><img decoding="async" class="wp-block-cover__image-background" alt="" src="https://s.w.org/images/core/5.8/forest.jpg" data-object-fit="cover" /><div class="wp-block-cover__inner-container is-layout-flow wp-block-cover-is-layout-flow">\n<h2 class="wp-block-heading alignwide has-text-color" style="color:#ffe074;font-size:64px">Forêt.</h2>\n\n\n\n<div class="wp-block-columns alignwide is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex">\n<div class="wp-block-column is-layout-flow wp-block-column-is-layout-flow" style="flex-basis:55%">\n<div style="height:330px" aria-hidden="true" class="wp-block-spacer"></div>\n\n\n\n<p class="has-text-color wp-block-paragraph" style="color:#ffe074;font-size:12px;line-height:1.3"><em>Même un enfant sait combien la forêt est précieuse. L’odeur fraîche des arbres, à vous couper le souffle. L’écho des oiseaux volant au-dessus de cette magnitude dense. Un climat stable, une vie durable et diversifiée et une source de culture. Pourtant, les forêts et d’autres écosystèmes sont en péril, menacés de devenir des terres de culture, des pâturages ou des plantations.</em></p>\n</div>\n\n\n\n<div class="wp-block-column is-layout-flow wp-block-column-is-layout-flow"></div>\n</div>\n</div></div>\n";s:9:"protected";b:0;}s:4:"meta";O:8:"stdClass":10:{s:14:"_crdt_document";s:0:"";s:31:"jetpack_post_was_ever_published";b:0;s:13:"wpop_keywords";s:0:"";s:16:"wpop_description";s:35:"Bannière avec une citation en haut";s:19:"wpop_viewport_width";i:1200;s:16:"wpop_block_types";a:1:{i:0;s:0:"";}s:11:"wpop_locale";s:5:"fr_FR";s:15:"wpop_wp_version";s:0:"";s:25:"wpop_contains_block_types";s:75:"core/column,core/columns,core/cover,core/heading,core/paragraph,core/spacer";s:9:"footnotes";s:0:"";}s:14:"category_slugs";a:1:{i:0;s:6:"banner";}s:13:"keyword_slugs";a:2:{i:0;s:4:"core";i:1;s:8:"featured";}s:15:"pattern_content";s:1777:"<!-- wp:cover {"url":"https://s.w.org/images/core/5.8/forest.jpg","dimRatio":60,"minHeight":800,"align":"full"} -->\n<div class="wp-block-cover alignfull" style="min-height:800px"><span aria-hidden="true" class="wp-block-cover__background has-background-dim-60 has-background-dim"></span><img class="wp-block-cover__image-background" alt="" src="https://s.w.org/images/core/5.8/forest.jpg" data-object-fit="cover" /><div class="wp-block-cover__inner-container"><!-- wp:heading {"align":"wide","style":{"color":{"text":"#ffe074"},"typography":{"fontSize":"64px"}}} -->\n<h2 class="wp-block-heading alignwide has-text-color" style="color:#ffe074;font-size:64px">Forêt.</h2>\n<!-- /wp:heading -->\n\n<!-- wp:columns {"align":"wide"} -->\n<div class="wp-block-columns alignwide"><!-- wp:column {"width":"55%"} -->\n<div class="wp-block-column" style="flex-basis:55%"><!-- wp:spacer {"height":"330px"} -->\n<div style="height:330px" aria-hidden="true" class="wp-block-spacer"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:paragraph {"style":{"color":{"text":"#ffe074"},"typography":{"lineHeight":"1.3","fontSize":"12px"}}} -->\n<p class="has-text-color" style="color:#ffe074;font-size:12px;line-height:1.3"><em>Même un enfant sait combien la forêt est précieuse. L’odeur fraîche des arbres, à vous couper le souffle. L’écho des oiseaux volant au-dessus de cette magnitude dense. Un climat stable, une vie durable et diversifiée et une source de culture. Pourtant, les forêts et d’autres écosystèmes sont en péril, menacés de devenir des terres de culture, des pâturages ou des plantations.</em></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class="wp-block-column"></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div></div>\n<!-- /wp:cover -->";}i:13;O:8:"stdClass":7:{s:2:"id";i:1326;s:5:"title";O:8:"stdClass":1:{s:8:"rendered";s:5:"titre";}s:7:"content";O:8:"stdClass":2:{s:8:"rendered";s:608:"\n<h2 class="alignwide wp-block-heading" id="we-re-a-studio-in-berlin-with-an-international-practice-in-architecture-urban-planning-and-interior-design-we-believe-in-sharing-knowledge-and-promoting-dialogue-to-increase-the-creative-potential-of-collaboration" style="font-size:48px;line-height:1.1">Nous sommes un studio situé à Berlin, avec une forte expérience internationale dans les domaines de l’architecture, de l’urbanisme et de l’aménagement intérieur. Nous croyons au partage des connaissances et à la promotion du dialogue pour accroître le potentiel créatif de la collaboration.</h2>\n";s:9:"protected";b:0;}s:4:"meta";O:8:"stdClass":10:{s:14:"_crdt_document";s:0:"";s:31:"jetpack_post_was_ever_published";b:0;s:13:"wpop_keywords";s:18:"grand texte, titre";s:16:"wpop_description";s:14:"Texte du titre";s:19:"wpop_viewport_width";i:1200;s:16:"wpop_block_types";a:1:{i:0;s:12:"core/heading";}s:11:"wpop_locale";s:5:"fr_FR";s:15:"wpop_wp_version";s:0:"";s:25:"wpop_contains_block_types";s:12:"core/heading";s:9:"footnotes";s:0:"";}s:14:"category_slugs";a:1:{i:0;s:4:"text";}s:13:"keyword_slugs";a:2:{i:0;s:4:"core";i:1;s:8:"featured";}s:15:"pattern_content";s:709:"<!-- wp:heading {"align":"wide","style":{"typography":{"fontSize":"48px","lineHeight":"1.1"}}} -->\n<h2 class="alignwide" id="we-re-a-studio-in-berlin-with-an-international-practice-in-architecture-urban-planning-and-interior-design-we-believe-in-sharing-knowledge-and-promoting-dialogue-to-increase-the-creative-potential-of-collaboration" style="font-size:48px;line-height:1.1">Nous sommes un studio situé à Berlin, avec une forte expérience internationale dans les domaines de l’architecture, de l’urbanisme et de l’aménagement intérieur. Nous croyons au partage des connaissances et à la promotion du dialogue pour accroître le potentiel créatif de la collaboration.</h2>\n<!-- /wp:heading -->";}i:14;O:8:"stdClass":7:{s:2:"id";i:207567;s:5:"title";O:8:"stdClass":1:{s:8:"rendered";s:11:"Link in Bio";}s:7:"content";O:8:"stdClass":2:{s:8:"rendered";s:6668:"\n<div class="wp-block-group has-white-background-color has