k-cover is-light has-custom-content-position is-position-top-right wp-container-content-ceb7f5b3 wp-duotone-rgb137750-rgb210210210-1" style="padding-top:4vw;padding-right:4vw;padding-bottom:4vw;padding-left:4vw;min-height:75vh;aspect-ratio:unset;"><span aria-hidden="true" class="wp-block-cover__background has-background-dim"></span><img decoding="async" class="wp-block-cover__image-background wp-image-334" alt="" src="https://pd.w.org/2023/04/654642d52f20d6367.57324872.jpg" data-object-fit="cover" /><div class="wp-block-cover__inner-container is-layout-flow wp-block-cover-is-layout-flow">\n<div class="wp-block-group is-vertical is-content-justification-right is-nowrap is-layout-flex wp-container-core-group-is-layout-06b49a26 wp-block-group-is-layout-flex">\n<p class="has-text-color wp-block-paragraph" style="color:#e5683a;font-size:140px;font-style:normal;font-weight:800;letter-spacing:-6px;line-height:0.8;text-transform:uppercase">Wardell</p>\n\n\n\n<p class="has-text-color wp-block-paragraph" style="color:#e5683a;font-size:130px;font-style:normal;font-weight:800;letter-spacing:-6px;line-height:0.8;text-transform:uppercase">gray</p>\n\n\n\n<p class="has-text-align-center has-text-color wp-block-paragraph" style="color:#d09c9c;font-size:90px;font-style:normal;font-weight:800;letter-spacing:0px;line-height:1;text-transform:uppercase">Plays</p>\n\n\n\n<p class="has-text-align-center has-text-color wp-block-paragraph" style="color:#e59937;font-size:90px;font-style:normal;font-weight:800;letter-spacing:0px;line-height:0.8;text-transform:uppercase">Bebop &amp;</p>\n\n\n\n<p class="has-text-align-center has-text-color wp-block-paragraph" style="color:#e59937;font-size:90px;font-style:normal;font-weight:800;letter-spacing:0px;line-height:1;text-transform:uppercase">SWING</p>\n</div>\n</div></div>\n\n\n\n<div class="wp-block-group wp-container-content-d387280b is-vertical is-nowrap is-layout-flex wp-container-core-group-is-layout-b27f8d4a wp-block-group-is-layout-flex">\n<p class="has-text-color wp-block-paragraph" style="color:#e59937;font-size:18px;font-style:normal;font-weight:400;letter-spacing:0px;line-height:1.7">Wardell Gray was born in Oklahoma City, the youngest of four children. His early childhood years were spent in Oklahoma, before moving with his family to Detroit in 1929. </p>\n\n\n\n<p class="has-text-color wp-block-paragraph" style="color:#e59937;font-size:18px;font-style:normal;font-weight:400;letter-spacing:0px;line-height:1.7">In early 1935, Gray began attending Northeastern High School, and then transferred to Cass Technical High School, which is noted for having Donald Byrd, Lucky Thompson and Al McKibbon as alumni. </p>\n\n\n\n<div class="wp-block-buttons is-content-justification-left is-nowrap is-layout-flex wp-container-core-buttons-is-layout-af480da9 wp-block-buttons-is-layout-flex">\n<div class="wp-block-button has-custom-font-size is-style-outline is-style-outline--2" style="font-size:16px;font-style:normal;font-weight:700;letter-spacing:0px;text-transform:uppercase"><a class="wp-block-button__link has-text-color wp-element-button" style="border-radius:0px;color:#e59937;padding-top:16px;padding-right:32px;padding-bottom:16px;padding-left:32px">Listen Now</a></div>\n</div>\n\n\n\n<div style="height:7.5vw" aria-hidden="true" class="wp-block-spacer"></div>\n</div>\n</div>\n</div></div>\n";s:9:"protected";b:0;}s:4:"meta";O:8:"stdClass":10:{s:14:"_crdt_document";s:0:"";s:31:"jetpack_post_was_ever_published";b:0;s:13:"wpop_keywords";s:0:"";s:16:"wpop_description";s:0:"";s:19:"wpop_viewport_width";i:800;s:16:"wpop_block_types";a:1:{i:0;s:0:"";}s:11:"wpop_locale";s:5:"fr_FR";s:15:"wpop_wp_version";s:3:"6.2";s:25:"wpop_contains_block_types";s:73:"core/button,core/buttons,core/cover,core/group,core/paragraph,core/spacer";s:9:"footnotes";s:0:"";}s:14:"category_slugs";a:1:{i:0;s:6:"banner";}s:13:"keyword_slugs";a:1:{i:0;s:4:"core";}s:15:"pattern_content";s:6364:"<!-- wp:cover {"customOverlayColor":"#36220c","contentPos