k-column-is-layout-flow" style="padding-top:1em;padding-right:1em;padding-bottom:1em;padding-left:1em">\n<div class="wp-block-columns is-layout-flex wp-container-core-columns-is-layout-0e47273b wp-block-columns-is-layout-flex">\n<div class="wp-block-column is-layout-flow wp-block-column-is-layout-flow" style="flex-basis:320px">\n<p class="has-small-font-size wp-block-paragraph" style="line-height:1.6"><strong>Airplane</strong></p>\n\n\n\n<p class="has-small-font-size wp-block-paragraph" style="line-height:1.6">Copper wire, wood base. I created this piece in late 2008. For this work, I aimed to convey both the industrial heaviness of an airplane, but also the cloudlike floating quality you feel when you’re in one.</p>\n</div>\n</div>\n</div>\n</div>\n";s:9:"protected";b:0;}s:4:"meta";O:8:"stdClass":10:{s:14:"_crdt_document";s:0:"";s:31:"jetpack_post_was_ever_published";b:0;s:13:"wpop_keywords";s:0:"";s:16:"wpop_description";s:38:"Image on solid color with description.";s:19:"wpop_viewport_width";i:1200;s:16:"wpop_block_types";a:0:{}s:11:"wpop_locale";s:5:"en_US";s:15:"wpop_wp_version";s:0:"";s:25:"wpop_contains_block_types";s:61:"core/column,core/columns,core/cover,core/image,core/paragraph";s:9:"footnotes";s:0:"";}s:14:"category_slugs";a:2:{i:0;s:6:"images";i:1;s:4:"text";}s:13:"keyword_slugs";a:1:{i:0;s:8:"featured";}s:15:"pattern_content";s:1826:"<!-- wp:columns {"align":"full"} -->\n<div class="wp-block-columns alignfull"><!-- wp:column {"width":"50%"} -->\n<div class="wp-block-column" style="flex-basis:50%"><!-- wp:cover {"customOverlayColor":"#f6f6f6","minHeight":600} -->\n<div class="wp-block-cover has-background-dim" style="background-color:#f6f6f6;min-height:600px"><div class="wp-block-cover__inner-container"><!-- wp:image {"align":"center","id":571,"sizeSlug":"medium","linkDestination":"none"} -->\n<div class="wp-block-image"><figure class="aligncenter size-medium"><img src="https://s.w.org/patterns/files/2021/06/wire-sculpture-263x300.jpg" alt="" class="wp-image-571" /></figure></div>\n<!-- /wp:image --></div></div>\n<!-- /wp:cover --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {"verticalAlignment":"center","style":{"spacing":{"padding":{"top":"1em","right":"1em","bottom":"1em","left":"1em"}}}} -->\n<div class="wp-block-column is-vertically-aligned-center" style="padding-top:1em;padding-right:1em;padding-bottom:1em;padding-left:1em"><!-- wp:columns -->\n<div class="wp-block-columns"><!-- wp:column {"width":"320px"} -->\n<div class="wp-block-column" style="flex-basis:320px"><!-- wp:paragraph {"style":{"typography":{"lineHeight":"1.6"}},"fontSize":"small"} -->\n<p class="has-small-font-size" style="line-height:1.6"><strong>Airplane</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {"style":{"typography":{"lineHeight":"1.6"}},"fontSize":"small"} -->\n<p class="has-small-font-size" style="line-height:1.6">Copper wire, wood base. I created this piece in late 2008. For this work, I aimed to convey both the industrial heaviness of an airplane, but also the cloudlike floating quality you feel when you’re in one.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->";}i:20;O:8:"stdClass":7:{s:2:"id";i:526;s:5:"title";O:8:"stdClass":1:{s:8:"rendered";s:31:"Offset images with descriptions";}s:7:"content";O:8:"stdClass":2:{s:8:"rendered";s:3150:"\n<div class="wp-block-columns alignwide are-vertically-aligned-top is-layout-flex wp-container-core-columns-is-layout-6cb89fa2 wp-block-columns-is-layout-flex">\n<div class="wp-block-column is-vertically-aligned-top is-layout-flow wp-block-column-is-layout-flow">\n<div class="wp-block-group wp-container-content-231d8afb is-vertical is-content-justification-left is-nowrap is-layout-flex wp-container-core-group-is-layout-bd8ca46f wp-block-group-is-layout-flex" style="margin-top:0;margin-bottom:0">\n<figure class="wp-block-image size-large wp-container-content-0733e5d0"><img loading="lazy" decodin