	(75, 1, '2026-03-18 10:11:16', '2026-03-18 09:11:16', '<!-- wp:paragraph -->\n<p><strong># Eval-wordpress-theme-1</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Évaluation Wordpress Thème Niveau 1</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Travaux Pratiques (TP) guidé de l\'installation jusqu\'à un thème fonctionnel.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>## Préparation</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Faites un FORK de ce dépôt et nommez le "eval-wordpress-20260318-XX" (remplacez XX par vos initiales).</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>---</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>## TP : Création d\'un thème WordPress "From Scratch"</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>**Objectif :**</strong> Transformer une structure HTML statique en un thème WordPress dynamique.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>### Étape 1 : Environnement et Structure</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>1. &nbsp;<strong>**Installation :**</strong> Installez un WordPress à partir du docker-compose fourni.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>&nbsp; &nbsp; - Avant de démarrer les conteneurs, Renommez les : Remplacer <em>*DWWM2503*</em> par votre <em>*identifiant ARFP*</em></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>2. &nbsp;<strong>**Dossier du thème :**</strong> Créez un dossier nommé `tp-prenom-nom` dans `wp-content/themes/`.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>3. &nbsp;<strong>**Fichiers vitaux :**</strong> Créez les fichiers `style.css` et `index.php`.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>&nbsp; &nbsp; * <em>*Consigne :*</em> Le fichier CSS doit contenir l\'en-tête de commentaire obligatoire pour que le thème soit activable dans l\'administration.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>4. &nbsp;<strong>**Activation :**</strong> Activez votre thème depuis l\'onglet "Apparence".</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>---</p>\n<!-- /wp:paragraph -->', 'A-propos', '', 'publish', 'closed', 'closed', '', 'a-propos', '', '', '2026-03-18 10:11:52', '2026-03-18 09:11:52', '', 0, 'http://localhost/?page_id=75', 0, 'page', '', 0),
